mapper.update:
update mem_seckill_record
seckill_id = #{seckillId}, member_id = #{memberId}, member_no = #{memberNo}, member_name = #{memberName}, seckill_date = #{seckillDate}, payment_method = #{paymentMethod}, shares = #{shares}, total_amount = #{totalAmount}, status = #{status}, claim_time = #{claimTime}, claim_by = #{claimBy}, update_by = #{updateBy}, remark = #{remark}, update_time = sysdate()
where record_id = #{recordId}

UPDATE mem_seckill_record
SET status = #{status}, claim_time = sysdate(), claim_by = #{claimBy}, update_time = sysdate(), version = version + 1
WHERE record_id = #{recordId} AND del_flag = '0' AND version = #{version}

mapper.select:
select count(*) as totalPeople, coalesce(sum(r.shares), 0) as totalShares, coalesce(sum(r.total_amount), 0) as totalAmount, coalesce(sum(case when r.status = '1' and coalesce(cs.claimed_shares, 0) = 0 then coalesce(r.shares, 0) else coalesce(cs.claimed_shares, 0) end), 0) as claimedShares, count(case when (case when r.status = '1' and coalesce(cs.claimed_shares, 0) = 0 then coalesce(r.shares, 0) else coalesce(cs.claimed_shares, 0) end) > 0 then 1 end) as claimedPeople from mem_seckill_record r left join ( select record_id, sum(claim_shares) as claimed_shares from mem_seckill_claim_record where del_flag = '0' group by record_id ) cs on r.record_id = cs.record_id where r.del_flag = '0' and r.seckill_id = #{seckillId} and r.member_no like concat('%', #{memberNo}, '%')
AND r.seckill_date >= #{params.beginTime}
AND r.seckill_date < DATE_ADD(#{params.endTime}, INTERVAL 1 DAY)

select member_id
from mem_seckill_record
where del_flag = '0'
  and dept_id = #{deptId}
  and seckill_id = #{seckillId}

      and seckill_date >= #{seckillDate} and seckill_date < DATE_ADD(#{seckillDate}, INTERVAL 1 DAY)
